-- 创建 products 表（保持原结构不变）
CREATE TABLE products (
    id INT AUTO_INCREMENT PRIMARY KEY COMMENT '主键ID',
    name VARCHAR(50) NOT NULL COMMENT '商品名称',
    image_url VARCHAR(255) COMMENT '图片URL',
    specification VARCHAR(20) NOT NULL COMMENT '类型：新鲜蔬菜、有机蔬菜、新鲜水果',
    stock INT DEFAULT 0 COMMENT '库存',
    price DECIMAL(10,2) NOT NULL COMMENT '价格',
    click_count INT DEFAULT 0 COMMENT '点击数',
    status VARCHAR(4) NOT NULL COMMENT '状态：上架或下架'
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COMMENT='商品表';

-- 增加产家/产地和商品简介字段（修正拼写错误：discription → description）
ALTER TABLE products 
ADD COLUMN producer VARCHAR(100) NOT NULL DEFAULT '未知' COMMENT '产家/产地' AFTER name,
ADD COLUMN description VARCHAR(500) NOT NULL DEFAULT '暂无简介' COMMENT '商品简介' AFTER image_url;

